param([string]`$AutoDelegationConfigPath = 'config/auto-delegation.json', [string]`$OrchestratorConfigPath = 'config/orchestrator.json'); `$ErrorActionPreference = 'Continue'; function Write-Status { param([string]`$Message); Write-Host '[ORCHESTRATOR] ' `$Message -ForegroundColor Green }; function Write-Info { param([string]`$Message); Write-Host '[INFO] ' `$Message -ForegroundColor Cyan }; function Write-ErrorMsg { param([string]`$Message); Write-Host '[ERROR] ' `$Message -ForegroundColor Red }; Write-Info 'Loading auto-delegation router module...'; try { Import-Module '.\skills\auto-delegation-router\auto-delegation-router.ps1' -Force; Write-Status 'Auto-delegation router module loaded successfully' } catch { Write-ErrorMsg 'Failed to load auto-delegation router: ' `$_; exit 1 }; Write-Info 'Enabling auto-delegation...'; try { `$result = Enable-AutoDelegation -ConfigPath `$AutoDelegationConfigPath; Write-Status 'Auto-delegation enabled: ' `$result.Status } catch { Write-ErrorMsg 'Failed to enable auto-delegation: ' `$_; exit 1 }; Write-Info 'Verifying orchestrator configuration...'; if (Test-Path `$OrchestratorConfigPath) { try { `$orchestratorConfig = Get-Content `$OrchestratorConfigPath | ConvertFrom-Json; Write-Status 'Orchestrator activation mode: ' `$orchestratorConfig.activation_mode; Write-Status 'Orchestrator active: ' `$orchestratorConfig.active } catch { Write-ErrorMsg 'Failed to read orchestrator configuration: ' `$_ } } else { Write-ErrorMsg 'Orchestrator configuration not found at ' `$OrchestratorConfigPath }; Write-Status 'Stack ready for automated operations'; Write-Status 'Session initialization complete'; exit 0
